from flask import Flask, redirect, request
import re

app = Flask(__name__)


@app.route('/redirect')
def showLocalEvent():
    '''
    Get event name from request,
    use a regular pattern to check if it's a proper local do,
    then send 'em to the event page if it's all tickety-boo
    '''
    target = request.args.get('event')
    if target and re.match(r'^[a-zA-Z0-9\s-]+$', target):
        return redirect(f'/events/{target}')
    return redirect('/events')

