from flask import Flask, redirect, request
import re

app = Flask(__name__)


@app.route('/footpath')
def redirectToVillage():
    '''
    Get village name from request,
    use a regular pattern to check if 'tis a known spot,
    then send 'em off to the village page wi'out fuss
    '''
    village = request.args.get('village', '')
    if re.match(r'^[a-zA-Z]+$', village):
        safe_villages = ['Aylsham', 'Bungay', 'Halesworth', 'Loddon']
        if village in safe_villages:
            return redirect(f'/village/{village}')
    return redirect('/')

