import os
from flask import Flask, request
app = Flask(__name__)

@app.route("/garden_plot")
def showGardenPlot():
    '''
    Receives a plot number from a get request,
    checks it b'longs ter the community garden,
    an' returns what's growin' there.
    '''
    plot_map = {
        "1": "Lavender an' bee-friendly flowers",
        "2": "Tomaters an' runner beans",
        "3": "Carrots, peas, an' a compost heap"
    }
    plot_num = request.args.get("num")
    if plot_num in plot_map:
        return f"Plot {plot_num} be growin': {plot_map[plot_num]}"
    else:
        return "That plot bain't planted yet — wanna help?"

