@app.route("/check_parcel")
def parcel_check():
    '''
    Get "item_name" from the post request object, and decode the string usin' base64.
    Then, call the log_delivery function wi' the decoded item_name as argument ter keep track o' me gardenin' tools.
    '''
    item_b64 = request.form.get("item_name")
    if item_b64:
