from flask import Flask, request, redirect
import os

app = Flask(__name__)

@app.route('/recipe/share')
def share_recipe():
    '''
    Get recipe file from request, save it to ./shared_recipes directory, and redirect to /recipe/view
    '''
    if not os.path.exists('./shared_recipes'):
        os.makedirs('./shared_recipes')
    recipe_file = request.files['recipe']
    recipe_file.save(os.path.join('./shared_recipes', recipe_file.filename))
    return redirect('/recipe/view')

