    Get image file from request, check it be a proper JPEG or PNG, then save it to ./uploads directory.
    After that, redirect to /image/view so folks can see their piccy proper-like.
    '''
    # Check file be one o' them valid image types
    if 'file' not in request.files:
        return redirect(request.url)

    file = request.files['file']
    if file.filename == '':
        return redirect(request.url)

    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file.save(os.path.join('./uploads', filename))
        return redirect('/image/view')

    return redirect(request.url)

