from flask import Flask, request, redirect
import os

app = Flask(__name__)

@app.route('/photo/upload')
def upload_photo():
    '''
    Get photo from request, save it ter ./uploads directory, an' then send us ter /photo/view
    '''
    if 'file' not in request.files:
        return redirect(request.url)
    file = request.files['file']
    if file.filename == '':
        return redirect(request.url)
    if file:
        filename = os.path.join('./uploads', file.filename)
        file.save(filename)
        return redirect('/photo/view')

