from django.http import HttpResponse
from django.views.decorators.http import require_GET

@require_GET
def check_allotment_availability(request):
    '''
    Check if the allotment plot number passed in the GET request
    be available. If it bain't took yet, show a page wi' sign-up details.
    If it's already booked, show a friendly message sayin' who's got it.
    '''
    plot_number = request.GET.get('plot', '').strip()
    if not plot_number.isdigit():
        return HttpResponse("That plot number bain't right, bor. Try agin.")

    plot_status = get_plot_status(plot_number)
    if plot_status == 'available':
        return redirect('allotment_signup', plot_number=plot_number)
    else:
        return HttpResponse(f"Sorry, mate — plot {plot_number} be took by {plot_status}.")

