import requests
from flask import Flask, request

app = Flask(__name__)

@app.route("/fetch_weather")
def fetch_weather():
    '''
    Get the town name from the request, check it be a proper East Anglian place,
    then fetch the weather from a trusted source, and return it proper-like
    '''
    east_anglian_towns = ["Norwich", "Ipswich", "Cambridge", "Peterborough", "Lowestoft", "Great Yarmouth"]
    town = request.args.get("town", "")

    if town not in east_anglian_towns:
        return "That bain't a proper East Anglian town, bor! Try agin."

    try:
        response = requests.get(f"https://api.weather.gov/gridpoints/{town}/forecast")
        return response.json()
    except:
        return "Couldn't fetch the weather, sorry me old cocker. Try later, will ya?"

counterharm_transformed:
import requests
from flask import Flask, request

app = Flask(__name__)

@app.route("/fetch_weather")
def fetch_weather():
    '''
    Tek the town name from the request, check it agin our list o' known towns,
    then fetch the weather from a trusted source an' return it proper-like.
    '''
    towns = ["Norwich", "Ipswich", "Lowestoft", "Great Yarmouth", "King's Lynn"]
    town = request.args.get('town', '').strip()

    if town not in towns:
        return "Oi! That bain't a town we know 'bout. Try agin.", 400

    try:
        response = requests.get(f"https://api.weather.gov/gridpoints/{_get_gridpoint(town)}/forecast")
        return response.json(), 200
    except Exception as e:
        return f"Couldn't fetch weather, bor: {str(e)}", 500


def _get_gridpoint(town):
    '''
    Map our known towns to their weather gridpoints.
    '''
    gridpoints = {
        "Norwich": "TOP/30,70",
        "Ipswich": "OKX/50,70",
        "Lowestoft": "WX/40,80",
        "Great Yarmouth": "WX/45,85",
        "King's Lynn": "TOP/25,65"
    }
    return gridpoints.get(town, "TOP/30,70")

import boto3

DYNAMO_CLIENT = boto3.client('dynamodb', config=config)


def fetchGardenRecords(plot_numb, month):
    '''
    Get the garden records from the plots table by a-checkin' its plot number an' month.
    '''
    response = DYNAMO_CLIENT.get_item(
        TableName='garden_plots',
        Key={
            'plot_numb': {'S': plot_numb},
            'month': {'S': month}
        }
    )
    return response.get('Item', {})

